var e=[{id:`L3_1`,type:`dialog`,speaker:`RIVET_ESPR_ReinforcedA_NULL`,text:{KOREA:`레지나, 어때? 더 싸울 수 있겠어?`,JPN:`レジーナ、どう？　まだ戦える？`,ENG:`Regina, you good? Do you think you can still fight?`,TWN:`蕾佳娜，怎麼樣？你還能繼續打嗎？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RIVET_ESPR_ReinforcedA_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L4_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`꽤 지쳤어요. 힘이 돌아오지는 않았으니까요.`,JPN:`結構疲れましたわ。力が戻ってきてはいませんから。`,ENG:`I am exhausted. My powers have not returned yet.`,TWN:`我已經筋疲力盡了，因為力量還沒有恢復。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RIVET_ESPR_ReinforcedA_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`RIVET_ESPR_ReinforcedA_NULL`,text:{KOREA:`곤란한데~ 지금 저 녀석들에게 붙잡히면 온갖 험한 꼴 다 볼 텐데~`,JPN:`困ったな～今あいつらに捕まったら、本当に痛い目に会うよ～`,ENG:`That's not good. If they catch us now, we're gonna be in big trouble!`,TWN:`這下麻煩了～現在被那些傢伙抓住的話，一定會倒楣的～`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RIVET_ESPR_ReinforcedA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`그래요. 그리고 전 연체 동물 비슷한 무언가로 변하겠죠.`,JPN:`そうですわね。そして私は軟体動物みたいな何かになるんでしょうね。`,ENG:`Yes. And I will also become turn into those slugs.`,TWN:`是的。然後我或許會被變成某種軟體動物也說不定。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RIVET_ESPR_ReinforcedA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`하지만…….`,JPN:`ですが……`,ENG:`However...`,TWN:`但是……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`RIVET_ESPR_ReinforcedA_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`AGNES_ESPR_NULL_NULL`,text:{KOREA:`여행은 좀 어때, 부학회장님? 즐겁다고 말할 상황은 아닌가?`,JPN:`旅行はどう？　副学会長。楽しいと言える状況ではないかしら？`,ENG:`How is your journey going, Ms. Vice President? Not really in a fun situation, are you?`,TWN:`你的旅行怎麼樣，副學會長？情況說不上愉快嗎？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AGNES_ESPR_NULL_NULL`,face:`UNIT_LAUGH`},R:null}},sfx:`FX_CUTSCEN_NOISE`},{id:`L12_1`,type:`dialog`,speaker:`SILKY_NPC_ESPR2_NULL`,text:{KOREA:`세상에, 종교학부장님!`,JPN:`まあ、宗教学部長様！`,ENG:`Oh my! It's the Dean of Religion!`,TWN:`天啊，宗教學院院長！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SILKY_NPC_ESPR2_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L13_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`……역시, 신호를 보낸 사람은 당신이었나요.`,JPN:`……やはり、信号を送った人はあなただったのですか。`,ENG:`…I knew It was you who sent that signal.`,TWN:`……發訊號的人果然是你嗎。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SILKY_NPC_ESPR2_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`AGNES_ESPR_NULL_NULL`,text:{KOREA:`응? 실망했어?`,JPN:`あら？　ガッカリした？`,ENG:`Hmm? Are you disappointed it's me?`,TWN:`嗯？讓你失望了？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AGNES_ESPR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`REGINA_ESPR_NULL_NULL`,text:{KOREA:`아뇨. 잔해들이 들끓는 곳까지 저희를 찾아 올 사람은 지금으로선 몇 없으니까요.`,JPN:`いいえ。残骸がうようよしているところまで私たちを訪ねてくるような人は、今では数少ないですから。`,ENG:`No. Not many people would be willing to come visit us at this Remains-infested place.`,TWN:`沒有，因為現在沒有幾個人會來殘骸出沒的地方找我們。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SILKY_NPC_ESPR2_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`REGINA_ESPR_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L20_1`,type:`dialog`,speaker:`AGNES_ESPR_NULL_NULL`,text:{KOREA:`그렇구나. 그래도 아쉽네. 기쁘게 환영 받을 줄 알았는데.`,JPN:`そう？　それでも残念だわ。喜んで歓迎してくれると思ったのに。`,ENG:`I see. But still, what a shame. I was expecting you'd be happy to see me.`,TWN:`這樣啊。不過我還是有點遺憾。我還以為自己會受到歡迎。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AGNES_ESPR_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`AGNES_ESPR_NULL_NULL`,text:{KOREA:`우선, 힘들어 보이니까 거들어 주기로 할까. 접근하는 것들은 나에게 맡겨.`,JPN:`とりあえず、大変そうだから手伝うわ。近づいてくるものは私に任せて。`,ENG:`First of all, let me help out because you all look tired. I’ll take care of the approaching Remains.`,TWN:`首先，你看起來很累了，要不要我幫忙？靠近的這些傢伙都交給我吧。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`AGNES_ESPR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};